class Solution:
    def countSubarrays(self, nums, k):
        n = len(nums)
        cnt = 0
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += nums[j]
                if s * (j - i + 1) < k:
                    cnt += 1
                else:
                    break
        return cnt

