class Solution:
    def countSubarrays(self, nums, k):
        left = 0
        s = 0
        ans = 0
        for right, v in enumerate(nums):
            s += v
            while left <= right and s * (right - left + 1) >= k:
                s -= nums[left]
                left += 1
            ans += right - left + 1
        return ans

