var countSubarrays = function(nums, k) {
    let left = 0, s = 0, ans = 0;
    for (let right = 0; right < nums.length; right++) {
        s += nums[right];
        while (left <= right && s * (right - left + 1) >= k) {
            s -= nums[left];
            left++;
        }
        ans += right - left + 1;
    }
    return ans;
};
